    19→/// Unknown/default commit SHA (7 zeros)
    20→///
    21→/// Used when commit cannot be determined (git errors).
    22→/// All commit-related code derives the expected length from this constant.
    23→pub const JJRG_UNKNOWN_COMMIT: &str = "0000000";
