    81→// Validation helper functions
    82→
    83→/// Check if string contains only URL-safe base64 characters
    84→pub(crate) fn zjjrg_is_base64(s: &str) -> bool {
    85→    s.bytes().all(|b| JJRF_CHARSET.contains(&b))
    86→}
    87→
    88→/// Check if string is valid kebab-case (non-empty, lowercase alphanumeric with hyphens)
    89→pub(crate) fn zjjrg_is_kebab_case(s: &str) -> bool {
    90→    if s.is_empty() {
    91→        return false;
    92→    }
    93→    // Pattern: [a-z0-9]+(-[a-z0-9]+)*
    94→    let parts: Vec<&str> = s.split('-').collect();
    95→    for part in parts {
    96→        if part.is_empty() {
    97→            return false;
    98→        }
    99→        if !part.chars().all(|c| c.is_ascii_lowercase() || c.is_ascii_digit()) {
   100→            return false;
   101→        }
   102→    }
   103→    true
   104→}
   105→
   106→/// Check if string matches YYMMDD format
   107→pub(crate) fn zjjrg_is_yymmdd(s: &str) -> bool {
   108→    if s.len() != 6 {
   109→        return false;
   110→    }
   111→    s.chars().all(|c| c.is_ascii_digit())
   112→}
   113→
   114→/// Check if string matches YYMMDD-HHMM format
   115→pub(crate) fn zjjrg_is_yymmdd_hhmm(s: &str) -> bool {
   116→    if s.len() != 11 {
   117→        return false;
   118→    }
   119→    let parts: Vec<&str> = s.split('-').collect();
   120→    if parts.len() != 2 {
   121→        return false;
   122→    }
   123→    parts[0].len() == 6
   124→        && parts[0].chars().all(|c| c.is_ascii_digit())
   125→        && parts[1].len() == 4
   126→        && parts[1].chars().all(|c| c.is_ascii_digit())
   127→}
   128→
   129→/// Check if string is valid commit SHA format
   130→///
   131→/// Length is derived from JJRG_UNKNOWN_COMMIT constant.
   132→pub(crate) fn zjjrg_is_commit_sha(s: &str) -> bool {
   133→    s.len() == JJRG_UNKNOWN_COMMIT.len() && s.chars().all(|c| c.is_ascii_hexdigit())
   134→}
