   136→impl jjrg_Gallops {
   137→    /// Load Gallops from a file path
   138→    pub fn jjrg_load(path: &Path) -> Result<Self, String> {
   139→        let content = fs::read_to_string(path)
   140→            .map_err(|e| format!("Failed to read file '{}': {}", path.display(), e))?;
   141→
   142→        let gallops: jjrg_Gallops = serde_json::from_str(&content)
   143→            .map_err(|e| format!("Failed to parse JSON: {}", e))?;
   144→
   145→        Ok(gallops)
   146→    }
   147→
   148→    /// Save Gallops to a file path (atomic write)
   149→    pub fn jjrg_save(&self, path: &Path) -> Result<(), String> {
   150→        // Serialize to pretty JSON
   151→        let content = serde_json::to_string_pretty(self)
   152→            .map_err(|e| format!("Failed to serialize JSON: {}", e))?;
   153→
   154→        // Create temp file in same directory for atomic rename
   155→        let parent = path.parent().ok_or_else(|| "Invalid path: no parent directory".to_string())?;
   156→        let temp_path = parent.join(format!(".tmp.{}.json", std::process::id()));
   157→
   158→        // Write to temp file
   159→        let mut file = fs::File::create(&temp_path)
   160→            .map_err(|e| format!("Failed to create temp file: {}", e))?;
   161→        file.write_all(content.as_bytes())
   162→            .map_err(|e| format!("Failed to write temp file: {}", e))?;
   163→        file.sync_all()
   164→            .map_err(|e| format!("Failed to sync temp file: {}", e))?;
   165→        drop(file);
   166→
   167→        // Atomic rename
   168→        fs::rename(&temp_path, path)
   169→            .map_err(|e| format!("Failed to rename temp file to target: {}", e))?;
   170→
   171→        Ok(())
   172→    }
   173→
   174→    /// Validate the Gallops structure
   175→    ///
   176→    /// Returns Ok(()) if valid, Err(Vec<String>) with all validation errors otherwise.
   177→    pub fn jjrg_validate(&self) -> Result<(), Vec<String>> {
   178→        let mut errors = Vec::new();
   179→
   180→        // Rule 1: next_heat_seed must be 2 URL-safe base64 characters
   181→        if self.next_heat_seed.len() != 2 {
   182→            errors.push(format!(
   183→                "next_heat_seed must be 2 characters, got {}",
   184→                self.next_heat_seed.len()
   185→            ));
   186→        } else if !zjjrg_is_base64(&self.next_heat_seed) {
   187→            errors.push(format!(
   188→                "next_heat_seed contains invalid base64 characters: '{}'",
   189→                self.next_heat_seed
   190→            ));
   191→        }
   192→
   193→        // Rule 2: heats object exists (implicitly satisfied by struct)
   194→
   195→        // Validate each Heat
   196→        for (heat_key, heat) in &self.heats {
   197→            self.zjjrg_validate_heat(heat_key, heat, &mut errors);
   198→        }
   199→
   200→        if errors.is_empty() {
   201→            Ok(())
   202→        } else {
   203→            Err(errors)
   204→        }
   205→    }
   206→
   207→    fn zjjrg_validate_heat(&self, heat_key: &str, heat: &jjrg_Heat, errors: &mut Vec<String>) {
   208→        let heat_ctx = format!("Heat '{}'", heat_key);
   209→
   210→        // Rule 3: Heat key must match ₣[A-Za-z0-9_-]{2}
   211→        if !heat_key.starts_with('₣') {
   212→            errors.push(format!("{}: key must start with '₣'", heat_ctx));
   213→        } else {
   214→            let suffix = &heat_key[3..]; // ₣ is 3 bytes in UTF-8
   215→            if suffix.len() != 2 {
   216→                errors.push(format!(
   217→                    "{}: key must have 2 base64 chars after '₣', got {}",
   218→                    heat_ctx,
   219→                    suffix.len()
   220→                ));
   221→            } else if !zjjrg_is_base64(suffix) {
   222→                errors.push(format!(
   223→                    "{}: key contains invalid base64 characters",
   224→                    heat_ctx
   225→                ));
   226→            }
   227→        }
   228→
   229→        // Rule 4: Required Heat fields
   230→        // silks (non-empty kebab-case)
   231→        if !zjjrg_is_kebab_case(&heat.silks) {
   232→            errors.push(format!(
   233→                "{}: silks must be non-empty kebab-case, got '{}'",
   234→                heat_ctx, heat.silks
   235→            ));
   236→        }
   237→
   238→        // creation_time (YYMMDD)
   239→        if !zjjrg_is_yymmdd(&heat.creation_time) {
   240→            errors.push(format!(
   241→                "{}: creation_time must be YYMMDD format, got '{}'",
   242→                heat_ctx, heat.creation_time
   243→            ));
   244→        }
   245→
   246→        // status (validated by serde enum)
   247→
   248→        // next_pace_seed (3 URL-safe base64 characters)
   249→        if heat.next_pace_seed.len() != 3 {
   250→            errors.push(format!(
   251→                "{}: next_pace_seed must be 3 characters, got {}",
   252→                heat_ctx,
   253→                heat.next_pace_seed.len()
   254→            ));
   255→        } else if !zjjrg_is_base64(&heat.next_pace_seed) {
   256→            errors.push(format!(
   257→                "{}: next_pace_seed contains invalid base64 characters",
   258→                heat_ctx
   259→            ));
   260→        }
   261→
   262→        // Extract heat identity (base64 part without prefix) for pace validation
   263→        let heat_identity = if heat_key.starts_with('₣') && heat_key.len() >= 5 {
   264→            Some(&heat_key[3..]) // ₣ is 3 bytes
   265→        } else {
   266→            None
   267→        };
   268→
   269→        // Rule 5: order array and paces object must have identical key sets
   270→        let order_set: HashSet<&String> = heat.order.iter().collect();
   271→        let _paces_set: HashSet<&String> = heat.paces.keys().collect();
   272→
   273→        if order_set.len() != heat.order.len() {
   274→            errors.push(format!("{}: order array contains duplicate entries", heat_ctx));
   275→        }
   276→
   277→        let in_order_not_paces: Vec<_> = heat
   278→            .order
   279→            .iter()
   280→            .filter(|k| !heat.paces.contains_key(*k))
   281→            .collect();
   282→        let in_paces_not_order: Vec<_> = heat
   283→            .paces
   284→            .keys()
   285→            .filter(|k| !order_set.contains(k))
   286→            .collect();
   287→
   288→        if !in_order_not_paces.is_empty() {
   289→            errors.push(format!(
   290→                "{}: order contains keys not in paces: {:?}",
   291→                heat_ctx, in_order_not_paces
   292→            ));
   293→        }
   294→        if !in_paces_not_order.is_empty() {
   295→            errors.push(format!(
   296→                "{}: paces contains keys not in order: {:?}",
   297→                heat_ctx, in_paces_not_order
   298→            ));
   299→        }
   300→
   301→        // Validate each Pace
   302→        for (pace_key, pace) in &heat.paces {
   303→            self.zjjrg_validate_pace(&heat_ctx, heat_identity, pace_key, pace, errors);
   304→        }
   305→    }
   306→
   307→    fn zjjrg_validate_pace(
   308→        &self,
   309→        heat_ctx: &str,
   310→        heat_identity: Option<&str>,
   311→        pace_key: &str,
   312→        pace: &jjrg_Pace,
   313→        errors: &mut Vec<String>,
   314→    ) {
   315→        let pace_ctx = format!("{} Pace '{}'", heat_ctx, pace_key);
   316→
   317→        // Rule 6: Pace key must match ₢[A-Za-z0-9_-]{5}
   318→        if !pace_key.starts_with('₢') {
   319→            errors.push(format!("{}: key must start with '₢'", pace_ctx));
   320→        } else {
   321→            let suffix = &pace_key[3..]; // ₢ is 3 bytes in UTF-8
   322→            if suffix.len() != 5 {
   323→                errors.push(format!(
   324→                    "{}: key must have 5 base64 chars after '₢', got {}",
   325→                    pace_ctx,
   326→                    suffix.len()
   327→                ));
   328→            } else {
   329→                if !zjjrg_is_base64(suffix) {
   330→                    errors.push(format!(
   331→                        "{}: key contains invalid base64 characters",
   332→                        pace_ctx
   333→                    ));
   334→                }
   335→                // Pace must embed parent Heat identity (first 2 chars)
   336→                if let Some(heat_id) = heat_identity {
   337→                    if !suffix.starts_with(heat_id) {
   338→                        errors.push(format!(
   339→                            "{}: key must embed parent heat identity '{}', got '{}'",
   340→                            pace_ctx,
   341→                            heat_id,
   342→                            &suffix[..2.min(suffix.len())]
   343→                        ));
   344→                    }
   345→                }
   346→            }
   347→        }
   348→
   349→        // Rule 7: tacks must be non-empty array
   350→        if pace.tacks.is_empty() {
   351→            errors.push(format!("{}: tacks array must not be empty", pace_ctx));
   352→        }
   353→
   354→        // Validate each Tack
   355→        for (i, tack) in pace.tacks.iter().enumerate() {
   356→            self.zjjrg_validate_tack(&pace_ctx, i, tack, errors);
   357→        }
   358→    }
   359→
   360→    fn zjjrg_validate_tack(&self, pace_ctx: &str, index: usize, tack: &jjrg_Tack, errors: &mut Vec<String>) {
   361→        let tack_ctx = format!("{} Tack[{}]", pace_ctx, index);
   362→
   363→        // Rule 8: ts must be YYMMDD-HHMM
   364→        if !zjjrg_is_yymmdd_hhmm(&tack.ts) {
   365→            errors.push(format!(
   366→                "{}: ts must be YYMMDD-HHMM format, got '{}'",
   367→                tack_ctx, tack.ts
   368→            ));
   369→        }
   370→
   371→        // Rule 8: text must be non-empty
   372→        if tack.text.is_empty() {
   373→            errors.push(format!("{}: text must not be empty", tack_ctx));
   374→        }
   375→
   376→        // Rule 8: silks must be non-empty kebab-case
   377→        if !zjjrg_is_kebab_case(&tack.silks) {
   378→            errors.push(format!(
   379→                "{}: silks must be non-empty kebab-case, got '{}'",
   380→                tack_ctx, tack.silks
   381→            ));
   382→        }
   383→
   384→        // Rule 8: commit must be valid format (7 hex chars)
   385→        if !zjjrg_is_commit_sha(&tack.commit) {
   386→            errors.push(format!(
   387→                "{}: commit must be 7 hex characters, got '{}'",
   388→                tack_ctx, tack.commit
   389→            ));
   390→        }
   391→
   392→        // Rule 9: direction presence depends on state
   393→        match tack.state {
   394→            jjrg_PaceState::Bridled => {
   395→                match &tack.direction {
   396→                    None => {
   397→                        errors.push(format!(
   398→                            "{}: direction is required when state is 'bridled'",
   399→                            tack_ctx
   400→                        ));
   401→                    }
   402→                    Some(d) if d.is_empty() => {
   403→                        errors.push(format!(
   404→                            "{}: direction must not be empty when state is 'bridled'",
   405→                            tack_ctx
   406→                        ));
   407→                    }
   408→                    _ => {}
   409→                }
   410→            }
   411→            _ => {
   412→                if tack.direction.is_some() {
   413→                    errors.push(format!(
   414→                        "{}: direction must be absent when state is not 'bridled'",
   415→                        tack_ctx
   416→                    ));
   417→                }
   418→            }
   419→        }
   420→    }
   421→}
