   423→// ===== Seed Increment Helpers =====
   424→
   425→/// Increment a base64 seed string (with carry)
   426→/// Works for both 2-char (heat) and 3-char (pace) seeds
   427→pub(crate) fn zjjrg_increment_seed(seed: &str) -> String {
   428→    let mut chars: Vec<u8> = seed.bytes().collect();
   429→    let mut carry = true;
   430→
   431→    // Process from right to left
   432→    for i in (0..chars.len()).rev() {
   433→        if !carry {
   434→            break;
   435→        }
   436→
   437→        // Find current position in charset
   438→        let pos = JJRF_CHARSET.iter().position(|&c| c == chars[i]).unwrap_or(0);
   439→
   440→        if pos == 63 {
   441→            // Wrap around
   442→            chars[i] = JJRF_CHARSET[0];
   443→            // carry remains true
   444→        } else {
   445→            chars[i] = JJRF_CHARSET[pos + 1];
   446→            carry = false;
   447→        }
   448→    }
   449→
   450→    String::from_utf8(chars).unwrap_or_else(|_| seed.to_string())
   451→}
   452→
   453→/// Capture current commit SHA
   454→///
   455→/// Runs `git rev-parse --short=N HEAD` where N is derived from JJRG_UNKNOWN_COMMIT length.
   456→/// Returns JJRG_UNKNOWN_COMMIT on error (e.g., not in a git repo).
   457→pub fn jjrg_capture_commit_sha() -> String {
   458→    use std::process::Command;
   459→
   460→    let short_arg = format!("--short={}", JJRG_UNKNOWN_COMMIT.len());
   461→    match Command::new("git")
   462→        .args(["rev-parse", &short_arg, "HEAD"])
   463→        .output()
   464→    {
   465→        Ok(output) if output.status.success() => {
   466→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   467→        }
   468→        _ => JJRG_UNKNOWN_COMMIT.to_string(),
   469→    }
   470→}
