   472→/// Create a new Tack with current timestamp and commit SHA
   473→///
   474→/// Centralizes Tack creation to ensure consistent timestamp/commit capture.
   475→/// All code creating new Tacks should use this helper.
   476→pub fn jjrg_make_tack(
   477→    state: jjrg_PaceState,
   478→    text: String,
   479→    silks: String,
   480→    direction: Option<String>,
   481→) -> jjrg_Tack {
   482→    jjrg_Tack {
   483→        ts: timestamp_full(),
   484→        state,
   485→        text,
   486→        silks,
   487→        commit: jjrg_capture_commit_sha(),
   488→        direction,
   489→    }
   490→}
