   596→impl jjrg_Gallops {
   597→    /// Nominate a new Heat
   598→    ///
   599→    /// Creates a new Heat with empty Pace structure and creates the paddock file.
   600→    pub fn jjrg_nominate(&mut self, args: jjrg_NominateArgs, base_path: &Path) -> Result<jjrg_NominateResult, String> {
   601→        // Validate silks is kebab-case
   602→        if !zjjrg_is_kebab_case(&args.silks) {
   603→            return Err(format!("silks must be kebab-case, got '{}'", args.silks));
   604→        }
   605→
   606→        // Validate created is YYMMDD
   607→        if !zjjrg_is_yymmdd(&args.created) {
   608→            return Err(format!("created must be YYMMDD format, got '{}'", args.created));
   609→        }
   610→
   611→        // Allocate Firemark from next_heat_seed
   612→        let firemark_str = format!("{}{}", FIREMARK_PREFIX, self.next_heat_seed);
   613→        let heat_id = self.next_heat_seed.clone();
   614→
   615→        // Compute paddock path
   616→        let paddock_file = format!(".claude/jjm/jjp_{}.md", heat_id);
   617→
   618→        // Create paddock file with template
   619→        let paddock_path = base_path.join(&paddock_file);
   620→        if let Some(parent) = paddock_path.parent() {
   621→            fs::create_dir_all(parent)
   622→                .map_err(|e| format!("Failed to create paddock directory: {}", e))?;
   623→        }
   624→
   625→        let paddock_content = format!(
   626→            "# Paddock: {}\n\n## Context\n\n(Describe the initiative's background and goals)\n\n## References\n\n(List relevant files, docs, or prior work)\n",
   627→            args.silks
   628→        );
   629→
   630→        fs::write(&paddock_path, paddock_content)
   631→            .map_err(|e| format!("Failed to write paddock file: {}", e))?;
   632→
   633→        // Create new Heat
   634→        let heat = jjrg_Heat {
   635→            silks: args.silks,
   636→            creation_time: args.created,
   637→            status: jjrg_HeatStatus::Current,
   638→            order: Vec::new(),
   639→            next_pace_seed: "AAA".to_string(),
   640→            paddock_file,
   641→            paces: BTreeMap::new(),
   642→        };
   643→
   644→        // Insert Heat
   645→        self.heats.insert(firemark_str.clone(), heat);
   646→
   647→        // Increment next_heat_seed
   648→        self.next_heat_seed = zjjrg_increment_seed(&self.next_heat_seed);
   649→
   650→        Ok(jjrg_NominateResult { firemark: firemark_str })
   651→    }
   652→
   653→    /// Slate a new Pace
   654→    ///
   655→    /// Adds a new Pace to a Heat with an initial Tack in rough state.
   656→    /// Positioning: use before/after/first to insert at specific location.
   657→    pub fn jjrg_slate(&mut self, args: jjrg_SlateArgs) -> Result<jjrg_SlateResult, String> {
   658→        // Validate silks is kebab-case
   659→        if !zjjrg_is_kebab_case(&args.silks) {
   660→            return Err(format!("silks must be kebab-case, got '{}'", args.silks));
   661→        }
   662→
   663→        // Validate text is non-empty
   664→        if args.text.is_empty() {
   665→            return Err("text must not be empty".to_string());
   666→        }
   667→
   668→        // Validate positioning mutual exclusivity
   669→        let position_count = [args.before.is_some(), args.after.is_some(), args.first]
   670→            .iter()
   671→            .filter(|&&x| x)
   672→            .count();
   673→        if position_count > 1 {
   674→            return Err("Only one of --before, --after, or --first may be specified".to_string());
   675→        }
   676→
   677→        // Parse and normalize firemark
   678→        let firemark = Firemark::jjrf_parse(&args.firemark)
   679→            .map_err(|e| format!("Invalid firemark: {}", e))?;
   680→        let firemark_key = firemark.jjrf_display();
   681→
   682→        // Verify Heat exists
   683→        let heat = self.heats.get_mut(&firemark_key)
   684→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   685→
   686→        // If --before or --after specified, validate target coronet exists
   687→        let insert_position = if let Some(ref before_str) = args.before {
   688→            let target = Coronet::jjrf_parse(before_str)
   689→                .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   690→            let target_key = target.jjrf_display();
   691→            let pos = heat.order.iter().position(|c| c == &target_key)
   692→                .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   693→            Some(pos) // Insert before this position
   694→        } else if let Some(ref after_str) = args.after {
   695→            let target = Coronet::jjrf_parse(after_str)
   696→                .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   697→            let target_key = target.jjrf_display();
   698→            let pos = heat.order.iter().position(|c| c == &target_key)
   699→                .ok_or_else(|| format!("Target coronet '{}' not found in heat", target_key))?;
   700→            Some(pos + 1) // Insert after this position
   701→        } else if args.first {
   702→            Some(0) // Insert at beginning
   703→        } else {
   704→            None // Append to end (default)
   705→        };
   706→
   707→        // Construct Coronet
   708→        let coronet_str = format!("{}{}{}", CORONET_PREFIX, firemark.jjrf_as_str(), heat.next_pace_seed);
   709→
   710→        // Create initial Tack and Pace
   711→        let tack = jjrg_make_tack(
   712→            jjrg_PaceState::Rough,
   713→            args.text,
   714→            args.silks,
   715→            None,
   716→        );
   717→        let pace = jjrg_Pace {
   718→            tacks: vec![tack],
   719→        };
   720→
   721→        // Insert into order at determined position
   722→        match insert_position {
   723→            Some(pos) => heat.order.insert(pos, coronet_str.clone()),
   724→            None => heat.order.push(coronet_str.clone()),
   725→        }
   726→        heat.paces.insert(coronet_str.clone(), pace);
   727→
   728→        // Increment next_pace_seed
   729→        heat.next_pace_seed = zjjrg_increment_seed(&heat.next_pace_seed);
   730→
   731→        Ok(jjrg_SlateResult { coronet: coronet_str })
   732→    }
   733→
   734→    /// Rail - reorder Paces within a Heat
   735→    ///
   736→    /// Supports two modes:
   737→    /// - Order mode: replace entire sequence with provided order array
   738→    /// - Move mode: relocate a single pace using positioning flags
   739→    pub fn jjrg_rail(&mut self, args: jjrg_RailArgs) -> Result<Vec<String>, String> {
   740→        // Parse and normalize firemark
   741→        let firemark = Firemark::jjrf_parse(&args.firemark)
   742→            .map_err(|e| format!("Invalid firemark: {}", e))?;
   743→        let firemark_key = firemark.jjrf_display();
   744→
   745→        // Verify Heat exists
   746→        let heat = self.heats.get_mut(&firemark_key)
   747→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   748→
   749→        // Mode detection: if move_coronet present, use move mode
   750→        if let Some(ref move_str) = args.move_coronet {
   751→            // Move mode validation
   752→            if !args.order.is_empty() {
   753→                return Err("Cannot combine --move with positional coronets".to_string());
   754→            }
   755→
   756→            // Parse and normalize move coronet
   757→            let move_coronet = Coronet::jjrf_parse(move_str)
   758→                .map_err(|e| format!("Invalid --move coronet: {}", e))?;
   759→            let move_key = move_coronet.jjrf_display();
   760→
   761→            // Validate move coronet exists in heat
   762→            if !heat.paces.contains_key(&move_key) {
   763→                return Err(format!("Pace {} not found in heat {}", move_key, firemark_key));
   764→            }
   765→
   766→            // Count positioning flags
   767→            let position_count = [
   768→                args.before.is_some(),
   769→                args.after.is_some(),
   770→                args.first,
   771→                args.last,
   772→            ].iter().filter(|&&x| x).count();
   773→
   774→            if position_count == 0 {
   775→                return Err("Move mode requires exactly one positioning flag".to_string());
   776→            }
   777→            if position_count > 1 {
   778→                let mut flags = Vec::new();
   779→                if args.before.is_some() { flags.push("--before"); }
   780→                if args.after.is_some() { flags.push("--after"); }
   781→                if args.first { flags.push("--first"); }
   782→                if args.last { flags.push("--last"); }
   783→                return Err(format!("Conflicting positioning flags: {}", flags.join(", ")));
   784→            }
   785→
   786→            // Determine target position and validate
   787→            let current_pos = heat.order.iter().position(|c| c == &move_key)
   788→                .ok_or_else(|| format!("Pace {} not in order array", move_key))?;
   789→
   790→            let new_pos = if args.first {
   791→                // Find first actionable pace (rough or bridled)
   792→                // If none found, use end of array (nothing actionable to precede)
   793→                let first_actionable_idx = heat.order.iter().position(|coronet| {
   794→                    if let Some(pace) = heat.paces.get(coronet) {
   795→                        if let Some(tack) = pace.tacks.first() {
   796→                            matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
   797→                        } else {
   798→                            false
   799→                        }
   800→                    } else {
   801→                        false
   802→                    }
   803→                });
   804→                // Use len() as fallback so adjustment logic works correctly for "end" position
   805→                let target_idx = first_actionable_idx.unwrap_or(heat.order.len());
   806→                // If moving from before target, the target shifts down after removal
   807→                if current_pos < target_idx {
   808→                    target_idx - 1
   809→                } else {
   810→                    target_idx
   811→                }
   812→            } else if args.last {
   813→                heat.order.len() - 1
   814→            } else if let Some(ref before_str) = args.before {
   815→                let target = Coronet::jjrf_parse(before_str)
   816→                    .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   817→                let target_key = target.jjrf_display();
   818→
   819→                if target_key == move_key {
   820→                    return Err("Cannot position pace relative to itself".to_string());
   821→                }
   822→
   823→                let target_pos = heat.order.iter().position(|c| c == &target_key)
   824→                    .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   825→
   826→                // If moving from before target, the target shifts down after removal
   827→                if current_pos < target_pos {
   828→                    target_pos - 1
   829→                } else {
   830→                    target_pos
   831→                }
   832→            } else if let Some(ref after_str) = args.after {
   833→                let target = Coronet::jjrf_parse(after_str)
   834→                    .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   835→                let target_key = target.jjrf_display();
   836→
   837→                if target_key == move_key {
   838→                    return Err("Cannot position pace relative to itself".to_string());
   839→                }
   840→
   841→                let target_pos = heat.order.iter().position(|c| c == &target_key)
   842→                    .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   843→
   844→                // If moving from before target, the target shifts down after removal
   845→                if current_pos < target_pos {
   846→                    target_pos // After removal, target is at target_pos-1, we want target_pos-1+1 = target_pos
   847→                } else {
   848→                    target_pos + 1
   849→                }
   850→            } else {
   851→                unreachable!()
   852→            };
   853→
   854→            // Remove from current position and insert at new position
   855→            heat.order.remove(current_pos);
   856→            heat.order.insert(new_pos, move_key);
   857→
   858→        } else {
   859→            // Order mode: replace entire sequence
   860→
   861→            // Normalize the input order (add prefix if missing)
   862→            let normalized_order: Result<Vec<String>, String> = args.order.iter()
   863→                .map(|c| {
   864→                    let coronet = Coronet::jjrf_parse(c)
   865→                        .map_err(|e| format!("Invalid coronet '{}': {}", c, e))?;
   866→                    Ok(coronet.jjrf_display())
   867→                })
   868→                .collect();
   869→            let new_order = normalized_order?;
   870→
   871→            // Validate count matches
   872→            if new_order.len() != heat.order.len() {
   873→                return Err(format!(
   874→                    "Order count mismatch: got {}, expected {}",
   875→                    new_order.len(),
   876→                    heat.order.len()
   877→                ));
   878→            }
   879→
   880→            // Validate no duplicates
   881→            let new_set: HashSet<&String> = new_order.iter().collect();
   882→            if new_set.len() != new_order.len() {
   883→                return Err("Order contains duplicate Coronets".to_string());
   884→            }
   885→
   886→            // Validate all Coronets exist in paces
   887→            for coronet in &new_order {
   888→                if !heat.paces.contains_key(coronet) {
   889→                    return Err(format!("Coronet '{}' not found in Heat's paces", coronet));
   890→                }
   891→            }
   892→
   893→            // Validate all Coronets embed correct parent Firemark
   894→            for coronet in &new_order {
   895→                let c = Coronet::jjrf_parse(coronet).unwrap();
   896→                if c.jjrf_parent_firemark().jjrf_display() != firemark_key {
   897→                    return Err(format!(
   898→                        "Coronet '{}' does not embed parent Heat '{}'",
   899→                        coronet, firemark_key
   900→                    ));
   901→                }
   902→            }
   903→
   904→            // Replace order
   905→            heat.order = new_order;
   906→        }
   907→
   908→        // Return the new order
   909→        Ok(heat.order.clone())
   910→    }
   911→
   912→    /// Tally - add a new Tack to a Pace
   913→    ///
   914→    /// Prepends a new Tack with state transition and/or plan refinement.
   915→    pub fn jjrg_tally(&mut self, args: jjrg_TallyArgs) -> Result<(), String> {
   916→        // Parse and normalize coronet
   917→        let coronet = Coronet::jjrf_parse(&args.coronet)
   918→            .map_err(|e| format!("Invalid coronet: {}", e))?;
   919→        let coronet_key = coronet.jjrf_display();
   920→
   921→        // Extract parent Firemark
   922→        let firemark = coronet.jjrf_parent_firemark();
   923→        let firemark_key = firemark.jjrf_display();
   924→
   925→        // Verify Heat exists
   926→        let heat = self.heats.get_mut(&firemark_key)
   927→            .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   928→
   929→        // Verify Pace exists
   930→        let pace = heat.paces.get_mut(&coronet_key)
   931→            .ok_or_else(|| format!("Pace '{}' not found", coronet_key))?;
   932→
   933→        // Read current Tack
   934→        let current_tack = pace.tacks.first()
   935→            .ok_or_else(|| "Pace has no tacks (should never happen)".to_string())?;
   936→
   937→        // Determine new state
   938→        let new_state = args.state.clone().unwrap_or_else(|| current_tack.state.clone());
   939→
   940→        // Determine new direction
   941→        let new_direction = match (&args.state, &new_state) {
   942→            // State explicitly set to bridled: direction required
   943→            (Some(jjrg_PaceState::Bridled), _) => {
   944→                match &args.direction {
   945→                    Some(d) if !d.is_empty() => Some(d.clone()),
   946→                    Some(_) => return Err("direction must not be empty when state is bridled".to_string()),
   947→                    None => return Err("direction is required when state is bridled".to_string()),
   948→                }
   949→            }
   950→            // State explicitly set to something other than bridled: direction forbidden
   951→            (Some(_), _) => {
   952→                if args.direction.is_some() {
   953→                    return Err("direction must be absent when state is not bridled".to_string());
   954→                }
   955→                None
   956→            }
   957→            // State inherited and was bridled: inherit direction
   958→            (None, jjrg_PaceState::Bridled) => {
   959→                args.direction.or_else(|| current_tack.direction.clone())
   960→            }
   961→            // State inherited and was not bridled: no direction
   962→            (None, _) => None,
   963→        };
   964→
   965→        // Determine new text
   966→        let new_text = args.text.unwrap_or_else(|| current_tack.text.clone());
   967→        if new_text.is_empty() {
   968→            return Err("text must not be empty".to_string());
   969→        }
   970→
   971→        // Create new Tack (inheriting silks from current tack)
   972→        let new_tack = jjrg_make_tack(
   973→            new_state,
   974→            new_text,
   975→            current_tack.silks.clone(),
   976→            new_direction,
   977→        );
   978→
   979→        // Prepend to tacks array
   980→        pace.tacks.insert(0, new_tack);
   981→
   982→        Ok(())
   983→    }
